import { createAuthSecurityRuntime } from "../lib/auth-security-runtime.js";
import { createSecurityEventsRuntime } from "../lib/security-events-runtime.js";
import { createUserAccessRuntime } from "../lib/user-access-runtime.js";
import { createUserPreferencesRuntime } from "../lib/user-preferences-runtime.js";
import { createUserProfileRuntime } from "../lib/user-profile-runtime.js";
import { createUserSessionSecurityRuntime } from "../lib/user-session-security-runtime.js";
import { assertRequiredDependencies } from "./assert-required-dependencies.js";

const USER_RUNTIME_DEPENDENCY_KEYS = [
  "AccessRole",
  "PermissionId",
  "addOwnerRoleLabel",
  "appendAuditLog",
  "authFailedBurstCritical",
  "authFailedBurstWarning",
  "authFailedByIpCounter",
  "buildAnalyticsRange",
  "buildCommentTargetInfo",
  "buildOtpAuthUrl",
  "can",
  "computeEffectiveAccessRole",
  "computeGrants",
  "createEnrollmentToken",
  "createHash",
  "createRevisionToken",
  "createSecurityEventPayload",
  "createSystemAuditReq",
  "dashboardHomeRoleIds",
  "dashboardWidgetIds",
  "dataEncryptionKeyring",
  "dataRepository",
  "decryptStringWithKeyring",
  "defaultPermissionsForRole",
  "excessiveSessionsWarning",
  "expandLegacyPermissions",
  "filterAnalyticsEvents",
  "generateTotpSecret",
  "getIpv4Network24",
  "getRequestIp",
  "getDispatchCriticalSecurityEventWebhook",
  "hashRecoveryCode",
  "isDiscordAvatarUrl",
  "isOwner",
  "isPlainObject",
  "isPrimaryOwner",
  "isRbacV2AcceptLegacyStar",
  "isRbacV2Enabled",
  "loadAnalyticsEvents",
  "loadComments",
  "loadOwnerIds",
  "loadPosts",
  "loadProjects",
  "loadSecurityEvents",
  "loadSiteSettings",
  "loadUploads",
  "loadUsers",
  "loadStoredUserPreferences",
  "metricsRegistry",
  "mfaEnrollmentTtlMs",
  "mfaFailedBurstWarning",
  "mfaFailedByUserCounter",
  "mfaIconUrl",
  "mfaIssuer",
  "mfaRecoveryCodePepper",
  "newNetworkLookbackMs",
  "normalizeAccessRole",
  "normalizeAnalyticsTypeFilter",
  "normalizeAvatarDisplay",
  "normalizePosts",
  "normalizeProjectReaderPreferences",
  "normalizeProjects",
  "normalizeSecurityEventStatus",
  "normalizeUploadsDeep",
  "parseAnalyticsRangeDays",
  "primaryAppOrigin",
  "removeOwnerRoleLabel",
  "resolveEffectiveUserAvatarUrl",
  "resolveUploadScopeAccess",
  "resolveUserAvatarRenderVersion",
  "sanitizeAssetUrl",
  "sanitizeFavoriteWorksByCategory",
  "sanitizePermissionsForStorage",
  "sanitizeSocials",
  "securityEventSeverity",
  "securityEventStatus",
  "selectRecentApprovedComments",
  "sessionIndexTouchMinIntervalMs",
  "sessionIndexTouchTsBySid",
  "sessionStore",
  "shouldSyncDiscordAvatarToStoredUser",
  "upsertSecurityEvent",
  "userPreferencesDensitySet",
  "userPreferencesThemeModeSet",
  "verifyTotpCode",
  "writeAllowedUsers",
  "writeStoredUserPreferences",
  "writeUsers",
];

export const createUserRuntimeBundle = (dependencies = {}) => {
  assertRequiredDependencies("createUserRuntimeBundle", dependencies, USER_RUNTIME_DEPENDENCY_KEYS);

  const userSessionSecurityRuntime = createUserSessionSecurityRuntime({
    dataEncryptionKeyring: dependencies.dataEncryptionKeyring,
    dataRepository: dependencies.dataRepository,
    decryptStringWithKeyring: dependencies.decryptStringWithKeyring,
    metricsRegistry: dependencies.metricsRegistry,
    sessionStore: dependencies.sessionStore,
  });

  let userAccessRuntime = null;

  const securityEventsRuntime = createSecurityEventsRuntime({
    appendAuditLog: dependencies.appendAuditLog,
    createSecurityEventPayload: dependencies.createSecurityEventPayload,
    createSystemAuditReq: dependencies.createSystemAuditReq,
    dispatchCriticalSecurityEventWebhook: (...args) =>
      dependencies.getDispatchCriticalSecurityEventWebhook()?.(...args),
    getIpv4Network24: dependencies.getIpv4Network24,
    getRequestIp: dependencies.getRequestIp,
    isAdminUser: (...args) => userAccessRuntime?.isAdminUser?.(...args),
    loadSecurityEvents: dependencies.loadSecurityEvents,
    loadUserSessionIndexRecords: userSessionSecurityRuntime.loadUserSessionIndexRecords,
    metricsRegistry: dependencies.metricsRegistry,
    newNetworkLookbackMs: dependencies.newNetworkLookbackMs,
    normalizeSecurityEventStatus: dependencies.normalizeSecurityEventStatus,
    securityEventSeverity: dependencies.securityEventSeverity,
    securityEventStatus: dependencies.securityEventStatus,
    upsertSecurityEvent: dependencies.upsertSecurityEvent,
    writeSecurityEvents: (events) => {
      if (dependencies.dataRepository?.writeSecurityEvents) {
        dependencies.dataRepository.writeSecurityEvents(events);
      }
    },
  });

  const userPreferencesRuntime = createUserPreferencesRuntime({
    dashboardHomeRoleIds: dependencies.dashboardHomeRoleIds,
    dashboardWidgetIds: dependencies.dashboardWidgetIds,
    isPlainObject: dependencies.isPlainObject,
    loadStoredUserPreferences: dependencies.loadStoredUserPreferences,
    normalizeProjectReaderPreferences: dependencies.normalizeProjectReaderPreferences,
    userPreferencesDensitySet: dependencies.userPreferencesDensitySet,
    userPreferencesThemeModeSet: dependencies.userPreferencesThemeModeSet,
    writeStoredUserPreferences: dependencies.writeStoredUserPreferences,
  });

  const authSecurityRuntime = createAuthSecurityRuntime({
    authFailedBurstCritical: dependencies.authFailedBurstCritical,
    authFailedBurstWarning: dependencies.authFailedBurstWarning,
    authFailedByIpCounter: dependencies.authFailedByIpCounter,
    buildOtpAuthUrl: dependencies.buildOtpAuthUrl,
    createEnrollmentToken: dependencies.createEnrollmentToken,
    emitSecurityEvent: securityEventsRuntime.emitSecurityEvent,
    excessiveSessionsWarning: dependencies.excessiveSessionsWarning,
    generateTotpSecret: dependencies.generateTotpSecret,
    getIpv4Network24: dependencies.getIpv4Network24,
    getRequestIp: dependencies.getRequestIp,
    getUserTotpSecret: userSessionSecurityRuntime.getUserTotpSecret,
    hashRecoveryCode: dependencies.hashRecoveryCode,
    listActiveSessionsForUser: userSessionSecurityRuntime.listActiveSessionsForUser,
    loadSiteSettings: dependencies.loadSiteSettings,
    loadUserMfaTotpRecord: userSessionSecurityRuntime.loadUserMfaTotpRecord,
    loadUserSessionIndexRecords: userSessionSecurityRuntime.loadUserSessionIndexRecords,
    metricsRegistry: dependencies.metricsRegistry,
    mfaEnrollmentTtlMs: dependencies.mfaEnrollmentTtlMs,
    mfaFailedBurstWarning: dependencies.mfaFailedBurstWarning,
    mfaFailedByUserCounter: dependencies.mfaFailedByUserCounter,
    mfaIconUrl: dependencies.mfaIconUrl,
    mfaIssuer: dependencies.mfaIssuer,
    mfaRecoveryCodePepper: dependencies.mfaRecoveryCodePepper,
    newNetworkLookbackMs: dependencies.newNetworkLookbackMs,
    primaryAppOrigin: dependencies.primaryAppOrigin,
    sanitizeAssetUrl: dependencies.sanitizeAssetUrl,
    securityEventSeverity: dependencies.securityEventSeverity,
    sessionIndexTouchMinIntervalMs: dependencies.sessionIndexTouchMinIntervalMs,
    sessionIndexTouchTsBySid: dependencies.sessionIndexTouchTsBySid,
    shouldEmitSecurityRuleEvent: securityEventsRuntime.shouldEmitSecurityRuleEvent,
    upsertUserSessionIndexRecord: userSessionSecurityRuntime.upsertUserSessionIndexRecord,
    verifyTotpCode: dependencies.verifyTotpCode,
    writeUserMfaTotpRecord: userSessionSecurityRuntime.writeUserMfaTotpRecord,
  });

  userAccessRuntime = createUserAccessRuntime({
    AccessRole: dependencies.AccessRole,
    PermissionId: dependencies.PermissionId,
    addOwnerRoleLabel: dependencies.addOwnerRoleLabel,
    buildAnalyticsRange: dependencies.buildAnalyticsRange,
    buildCommentTargetInfo: dependencies.buildCommentTargetInfo,
    can: dependencies.can,
    computeEffectiveAccessRole: dependencies.computeEffectiveAccessRole,
    computeGrants: dependencies.computeGrants,
    createHash: dependencies.createHash,
    defaultPermissionsForRole: dependencies.defaultPermissionsForRole,
    expandLegacyPermissions: dependencies.expandLegacyPermissions,
    filterAnalyticsEvents: dependencies.filterAnalyticsEvents,
    isOwner: dependencies.isOwner,
    isPrimaryOwner: dependencies.isPrimaryOwner,
    isRbacV2AcceptLegacyStar: dependencies.isRbacV2AcceptLegacyStar,
    isRbacV2Enabled: dependencies.isRbacV2Enabled,
    loadAnalyticsEvents: dependencies.loadAnalyticsEvents,
    loadComments: dependencies.loadComments,
    loadOwnerIds: dependencies.loadOwnerIds,
    loadPosts: dependencies.loadPosts,
    loadProjects: dependencies.loadProjects,
    loadUsers: dependencies.loadUsers,
    normalizeAccessRole: dependencies.normalizeAccessRole,
    normalizeAnalyticsTypeFilter: dependencies.normalizeAnalyticsTypeFilter,
    normalizeAvatarDisplay: dependencies.normalizeAvatarDisplay,
    normalizePosts: dependencies.normalizePosts,
    normalizeProjects: dependencies.normalizeProjects,
    normalizeUploadsDeep: dependencies.normalizeUploadsDeep,
    parseAnalyticsRangeDays: dependencies.parseAnalyticsRangeDays,
    primaryAppOrigin: dependencies.primaryAppOrigin,
    removeOwnerRoleLabel: dependencies.removeOwnerRoleLabel,
    resolveUploadScopeAccess: dependencies.resolveUploadScopeAccess,
    sanitizeFavoriteWorksByCategory: dependencies.sanitizeFavoriteWorksByCategory,
    sanitizePermissionsForStorage: dependencies.sanitizePermissionsForStorage,
    sanitizeSocials: dependencies.sanitizeSocials,
    selectRecentApprovedComments: dependencies.selectRecentApprovedComments,
    writeAllowedUsers: dependencies.writeAllowedUsers,
    writeUsers: dependencies.writeUsers,
  });

  const userProfileRuntime = createUserProfileRuntime({
    AccessRole: dependencies.AccessRole,
    addOwnerRoleLabel: dependencies.addOwnerRoleLabel,
    computeEffectiveAccessRole: dependencies.computeEffectiveAccessRole,
    computeGrants: dependencies.computeGrants,
    createRevisionToken: dependencies.createRevisionToken,
    ensureOwnerUser: userAccessRuntime.ensureOwnerUser,
    enforceUserAccessInvariants: userAccessRuntime.enforceUserAccessInvariants,
    isDiscordAvatarUrl: dependencies.isDiscordAvatarUrl,
    isOwner: dependencies.isOwner,
    isRbacV2AcceptLegacyStar: dependencies.isRbacV2AcceptLegacyStar,
    isRbacV2Enabled: dependencies.isRbacV2Enabled,
    loadOwnerIds: dependencies.loadOwnerIds,
    loadUploads: dependencies.loadUploads,
    loadUsers: dependencies.loadUsers,
    normalizeAvatarDisplay: dependencies.normalizeAvatarDisplay,
    normalizeUsers: userAccessRuntime.normalizeUsers,
    permissionsForRead: userAccessRuntime.permissionsForRead,
    resolveEffectiveUserAvatarUrl: dependencies.resolveEffectiveUserAvatarUrl,
    resolveUserAvatarRenderVersion: dependencies.resolveUserAvatarRenderVersion,
    shouldSyncDiscordAvatarToStoredUser: dependencies.shouldSyncDiscordAvatarToStoredUser,
    syncAllowedUsers: userAccessRuntime.syncAllowedUsers,
    writeUsers: dependencies.writeUsers,
  });

  return {
    ...userSessionSecurityRuntime,
    ...securityEventsRuntime,
    ...userPreferencesRuntime,
    ...authSecurityRuntime,
    ...userAccessRuntime,
    ...userProfileRuntime,
  };
};

export default createUserRuntimeBundle;
